insert into knowledge_nodes (id, project_id, node_key, label, category, sub_label, facts, talkpoint, description, sort_order) values
  ('deca9438-17f7-5869-baaf-04c33d48a1be','00000000-0000-0000-0000-00000000b005','bcc','Bcons Center City','project','Tên pháp lý: Khu dân cư Bình An Đông Tây','[{"key":"Tên thương mại","value":"Bcons Center City"},{"key":"Tên pháp lý","value":"Khu dân cư Bình An Đông Tây"},{"key":"Chủ đầu tư","value":"Công ty CP Địa ốc Bcons"},{"key":"Vị trí","value":"Đường Thống Nhất / D11, P. Đông Hòa, TP.HCM (Dĩ An cũ)"},{"key":"Quỹ đất","value":"~3,2 ha / 32.000 m²"},{"key":"Quy mô","value":"2 tháp TM 36 tầng (The Twin) + 3 tháp căn hộ 29 tầng"},{"key":"Tổng căn hộ","value":"~1.940 căn (một số tài liệu ghi >1.800)"},{"key":"Khởi công","value":"28/6/2025"},{"key":"Bàn giao dự kiến","value":"Quý IV/2027"},{"key":"Định vị","value":"Khu phức hợp căn hộ – TMDV – office – shophouse"}]'::jsonb,'"Đừng bán Bcons Center City như một block căn hộ đơn lẻ. Hãy bán như một hệ phức hợp All-in-One: ở, mua sắm, giải trí, học tập, làm việc và khai thác cho thuê trong cùng một cụm."','Bcons Center City là khu phức hợp của Bcons tại Đông Hòa (Dĩ An cũ) — public theo tên pháp lý Khu dân cư Bình An Đông Tây. Đây là node trung tâm để đi từ tổng quan → pháp lý → quy hoạch → từng tháp → tiện ích → tài chính → xử lý phản đối. Bản map này đã hợp nhất: dữ liệu Q&A nội bộ (5 tháp, tầng hầm lệch tầng, 74 tiện ích, cầu đi bộ, ngân hàng) + lớp research mở rộng (sáp nhập hành chính về TP.HCM, hệ sinh thái công ty Bcons, đối thủ Dĩ An và các nhân tố tranh cãi đang diễn ra).',0),
  ('9f64d20c-b4b8-5eec-8194-c4a177df99c2','00000000-0000-0000-0000-00000000b005','dia-oc-bcons','Địa ốc Bcons','developer',null,'[{"key":"Pháp nhân","value":"Công ty Cổ phần Địa ốc Bcons"},{"key":"MST","value":"0314704166 — GCN cấp 28/10/2017"},{"key":"Trụ sở","value":"176/1–176/3 Nguyễn Văn Thương, P. Thạnh Mỹ Tây (Bình Thạnh cũ)"},{"key":"Đại diện pháp luật","value":"Ông Ngô Lưu Bình (cần đối chiếu ĐKDN mới nhất)"},{"key":"Vốn điều lệ","value":"Chưa tìm thấy công khai — cần xác minh"}]'::jsonb,'"Pháp nhân ký hợp đồng với Anh/Chị là Công ty CP Địa ốc Bcons — em luôn ghi đúng tên này trên mọi giấy tờ, còn Bcons Group là thương hiệu hệ sinh thái đứng sau."','Pháp nhân chủ đầu tư trực tiếp của Khu dân cư Bình An Đông Tây. Khi tư vấn, nên tách rõ pháp nhân CĐT dự án và thương hiệu Bcons Group để tránh nói lẫn giữa tập đoàn và pháp nhân ký hợp đồng. Lưu ý dữ liệu: người đại diện theo nguồn gần nhất là ông Ngô Lưu Bình (Phó Chủ tịch thường trực Bcons Group) — nguồn cũ ghi ông Lê Như Thạch, có thể đã thay đổi; vốn điều lệ chưa khóa được từ nguồn public.',1),
  ('55ca16aa-4d81-5f4a-9994-69f41c523d46','00000000-0000-0000-0000-00000000b005','bcons-group','Bcons Group','developer',null,'[{"key":"Hình thành","value":"2013 — tiền thân Cty TNHH TVTK & QLDA Hồng Ngọc"},{"key":"Hệ sinh thái","value":"Thiết kế – thi công – kinh doanh – vận hành – giáo dục"},{"key":"Tệp dự án","value":"Bcons City, Garden, Green View, Miền Đông, Suối Tiên, Polaris..."},{"key":"Kế hoạch","value":"Đã nộp hồ sơ chuẩn bị IPO"},{"key":"Mục tiêu công bố","value":"Doanh thu 1 tỷ USD năm 2026 (tuyên bố CĐT, chưa kiểm chứng)"}]'::jsonb,'"Bcons có lợi thế hệ sinh thái khép kín. Với phân khúc vừa túi tiền, yếu tố quan trọng là kiểm soát chi phí, tiến độ và khả năng vận hành sau bàn giao."','Bcons Group phát triển từ một công ty tư vấn thiết kế (2013) thành hệ sinh thái khép kín quanh làng đại học. Lợi thế cốt lõi với phân khúc vừa túi tiền: kiểm soát chi phí, tiến độ và vận hành sau bàn giao bằng chính các công ty thành viên. Các mục tiêu doanh thu tỷ USD là tuyên bố của CĐT — dùng để kể câu chuyện tham vọng, không dùng làm cam kết.',2),
  ('f1c5f18e-c8c4-5480-9801-987845969254','00000000-0000-0000-0000-00000000b005','le-nhu-thach','TS Lê Như Thạch','developer',null,'[{"key":"Vai trò","value":"Chủ tịch HĐQT Bcons Group"},{"key":"Sinh năm","value":"1977 — tốt nghiệp ĐH Bách Khoa TP.HCM, từng là giảng viên"},{"key":"Sở hữu","value":"78,9% Bcons Construction (12/2025)"},{"key":"Chức danh khác","value":"Phó CT Hiệp hội Xây dựng Bình Dương; HCMCONS (11/2025)"}]'::jsonb,null,'Người sáng lập và là gương mặt đại diện của Bcons — xuất thân kỹ thuật xây dựng và giảng dạy. Câu chuyện "nhà giáo làm bất động sản cho người trẻ quanh làng đại học" là chất liệu thương hiệu mạnh, nhưng các phát ngôn cá nhân không thay thế được văn bản pháp lý của dự án.',3),
  ('6ca120d4-9577-5550-83c2-dc082b93ccad','00000000-0000-0000-0000-00000000b005','bcons-construction','Bcons Construction','developer','⚠ Vốn điều lệ biến động mạnh — cần theo dõi','[{"key":"Pháp nhân","value":"Cty CP Đầu tư Xây dựng Bcons — MST 0312173537 (6/3/2013)"},{"key":"Vai trò","value":"Doanh nghiệp lõi hệ sinh thái; tổng thầu thi công các dự án Bcons"},{"key":"Biến động vốn","value":"1.349 tỷ (8/2024) → 2,37 tỷ (12/2025)"},{"key":"Thay đổi tên","value":"12/2025 đổi lại tên gốc Hồng Ngọc (theo CafeF)"},{"key":"Cổ đông 12/2025","value":"Lê Như Thạch 78,9% · Nguyễn Thị Lan Anh 10,55% · Nguyễn Thị Ngọc Khuê 10,55%"}]'::jsonb,'"Nếu khách hỏi về biến động vốn: thừa nhận có tái cơ cấu pháp nhân trong hệ sinh thái trước IPO, và chuyển trọng tâm về pháp nhân CĐT dự án + ngân hàng bảo lãnh — đó mới là hai chủ thể bảo vệ quyền lợi người mua."','Doanh nghiệp lõi của hệ sinh thái, đồng thời là đơn vị thi công. Điểm cần theo dõi nghiêm túc: vốn điều lệ giảm từ 1.349 tỷ về 2,37 tỷ trong 2024–2025 kèm đổi tên pháp nhân — có thể là tái cơ cấu trước IPO, nhưng khi khách hỏi về năng lực tài chính thì không được né.',4),
  ('efcfe6a8-569f-5609-9f9b-afa7fc700df5','00000000-0000-0000-0000-00000000b005','bcons-members','Công ty thành viên Bcons','developer',null,'[{"key":"Bcons Home","value":"Tiếp thị & phân phối (F1 nội bộ)"},{"key":"Bcons Service","value":"Vận hành quản lý tòa nhà"},{"key":"Bcons Education","value":"Giáo dục — vốn tăng 2 tỷ → 500 tỷ (2023), hệ trường BSchool"},{"key":"Khác","value":"Bcons Invest (đầu tư), Bcons Tech (thiết kế)"}]'::jsonb,null,'Chuỗi công ty thành viên giúp Bcons khép kín từ bán hàng đến vận hành. Lưu ý quan trọng: Bcons Service chính là đơn vị đứng tên hợp đồng vận hành gây tranh cãi tại Bcons Garden (2026) — sale cần nắm vụ việc này để trả lời chủ động (xem node rủi ro).',5),
  ('717d6d85-1faf-5f03-bcb7-016b26e8bc95','00000000-0000-0000-0000-00000000b005','foreign-partners','Đối tác quốc tế','developer',null,'[{"key":"A Asset Limited","value":"Thái Lan — thuộc Tập đoàn PPSN; hợp tác tháp thuộc KDC Bcons City 12ha"},{"key":"Mercuria","value":"SPV Nhật Bản"},{"key":"Ý nghĩa","value":"Tín hiệu vốn ngoại vào hệ sinh thái — mức độ tham gia từng dự án cần văn bản"}]'::jsonb,null,'Bcons có hợp tác với đối tác Thái (A Asset/PPSN) và Nhật (Mercuria) ở cấp hệ sinh thái/dự án thành phần. Với Center City, chưa có công bố đối tác ngoại tham gia trực tiếp — không suy diễn "vốn Nhật/Thái" cho dự án này khi chưa có văn bản.',6),
  ('c12d3fcb-a1e6-59e1-9fb5-e272c4f1c75c','00000000-0000-0000-0000-00000000b005','ocb-banks','Ngân hàng & PTTT','developer','⚠ Chưa thấy chứng thư bảo lãnh từng căn — cần bổ sung','[{"key":"Ngân hàng bảo lãnh","value":"OCB — ký hợp tác chiến lược tại kick-off 2/12/2025"},{"key":"OCB cho vay","value":"Áp dụng tất cả PTTT (theo Q&A)"},{"key":"Ngân hàng tài trợ vay","value":"VCB, MB, ACB, TPBank, Public Bank, BIDV"},{"key":"PTTT","value":"Theo tiến độ hoặc VTC 50% + vay 50%"},{"key":"Ưu đãi sales page","value":"VCB 0% lãi 18 tháng (cần văn bản hiệu lực)"},{"key":"Cần bổ sung","value":"Chứng thư bảo lãnh, điều kiện vay, lãi suất sau ưu đãi"}]'::jsonb,'"Đừng nói chung chung ''ngân hàng hỗ trợ''. Nói rõ: OCB bảo lãnh dự án, VCB/MB/ACB/TPBank/Public Bank/BIDV cho vay, áp dụng PTTT nào — và hẹn gửi chứng thư bảo lãnh khi ký HĐMB."','OCB là ngân hàng bảo lãnh công bố tại lễ kick-off 2/12/2025; nhiều ngân hàng lớn tham gia tài trợ vay. Tuy nhiên chưa tìm thấy số chứng thư bảo lãnh cụ thể cho từng người mua — đây là tài liệu khách có quyền yêu cầu khi ký HĐMB.',7),
  ('51544aff-0d5c-53bc-beec-433244e5e5fc','00000000-0000-0000-0000-00000000b005','legal-name','KDC Bình An Đông Tây','legal',null,'[{"key":"Tên pháp lý","value":"Khu dân cư Bình An Đông Tây"},{"key":"Tên thương mại","value":"Bcons Center City"},{"key":"Cách dùng","value":"Tra hồ sơ pháp lý, GPXD, văn bản đủ điều kiện bán"}]'::jsonb,'"Khi khách hỏi pháp lý, đừng chỉ nói tên thương mại. Hãy đưa tên pháp lý để khách thấy tư vấn có kiểm soát và có thể kiểm tra được."','Tên pháp lý là anchor dữ liệu quan trọng nhất. Tài liệu tư vấn chuyên nghiệp luôn ghi song song: Bcons Center City (thương mại) — Khu dân cư Bình An Đông Tây (pháp lý).',8),
  ('981288a1-c5d2-5feb-a089-065b0c96fd59','00000000-0000-0000-0000-00000000b005','legal-milestones','Mốc pháp lý 2024–2025','legal','⚠ Số văn bản từ báo/portal — cần đối chiếu bản gốc','[{"key":"Chấp thuận chủ trương","value":"QĐ 2284/QĐ-UBND ngày 2/8/2024 (UBND tỉnh Bình Dương)"},{"key":"Quy hoạch 1/500","value":"QĐ 7367/QĐ-UBND ngày 6/12/2024 (UBND TP Dĩ An)"},{"key":"Giấy phép xây dựng","value":"Số 3728/GPXD ngày 27/6/2025 (Sở Xây dựng Bình Dương)"},{"key":"Khởi công","value":"28/6/2025"},{"key":"Nguồn","value":"CafeLand + trang dự án — chưa đối chiếu công báo"}]'::jsonb,'"Dự án có chuỗi văn bản 2284 → 7367 → GPXD 3728 nối nhau trong chưa đầy một năm. Em sẽ gửi Anh/Chị bản scan từng văn bản — đó là cách kiểm tra nhanh nhất một dự án có pháp lý thật hay chỉ có lời kể."','Chuỗi mốc pháp lý của dự án theo nguồn báo chí/portal. Trình tự 2024–2025 khá nhanh và liền mạch: chủ trương → 1/500 → GPXD → khởi công ngay hôm sau. Trạng thái: partial — chỉ nâng lên verified khi có bản scan các quyết định gốc trong data room.',9),
  ('d0fa218d-fdd6-5cea-9a75-b52cac6b19b0','00000000-0000-0000-0000-00000000b005','legal-room','Bộ pháp lý cần khóa','legal','⚠ Legal room / data room — kiểm soát rủi ro','[{"key":"Pháp lý sales page","value":"Có nhắc sổ hồng sở hữu lâu dài"},{"key":"GPXD","value":"Nguồn sales từng ghi số — cần bản scan gốc"},{"key":"Văn bản cần có","value":"Chấp thuận chủ trương, 1/500, GPXD, bảo lãnh, đủ điều kiện bán"},{"key":"Quy tắc dùng","value":"Không quote văn bản nếu chưa có file gốc"}]'::jsonb,'"Pháp lý là khu vực không được sáng tạo. Có văn bản thì nói. Chưa có văn bản thì ghi rõ ''theo thông tin chủ đầu tư công bố'' và hẹn gửi bản scan."','Node này không tạo thêm câu chuyện bán hàng — nó kiểm soát rủi ro. Dự án có nhiều sales page sẽ dễ sinh sai lệch nếu đội tư vấn không dùng chung data room. Khuyến nghị: mỗi văn bản có mã tài liệu, ngày cập nhật, người kiểm tra và trạng thái đã có bản gốc / đang chờ / không dùng.',10),
  ('414ca02d-133b-50a1-90e3-986a21baa119','00000000-0000-0000-0000-00000000b005','du-dk-ban','Văn bản đủ điều kiện bán','legal','⚠ CHƯA tìm thấy — rủi ro cốt lõi giai đoạn booking','[{"key":"Trạng thái","value":"Không tìm thấy văn bản đủ điều kiện bán nhà ở HTTTL"},{"key":"Giai đoạn hiện tại","value":"Thi công móng + nhận booking/giữ chỗ"},{"key":"Ký HĐMB dự kiến","value":"~7/2026 (theo kế hoạch CĐT)"},{"key":"Quyền của khách","value":"Yêu cầu xem văn bản Sở Xây dựng trước khi xuống tiền lớn"}]'::jsonb,'"Hiện dự án nhận giữ chỗ thiện chí; HĐMB chỉ ký khi có văn bản đủ điều kiện bán của Sở Xây dựng (dự kiến 2026). Khoản giữ chỗ hoàn lại được — và Anh/Chị nên yêu cầu xem văn bản này trước khi xuống tiền lớn. Em nói rõ vì đây là quyền của Anh/Chị."','Đây là rủi ro pháp lý cốt lõi nhất ở thời điểm hiện tại: dự án đang nhận giữ chỗ khi chưa có văn bản đủ điều kiện bán nhà ở hình thành trong tương lai. Booking là thỏa thuận dân sự có thể hoàn lại — không phải HĐMB, và không được mô tả như "đã mở bán chính thức".',11),
  ('8fd98244-d915-57da-ae3d-550447b98729','00000000-0000-0000-0000-00000000b005','sap-nhap','Sáp nhập hành chính 1/7/2025','legal',null,'[{"key":"Hiệu lực","value":"1/7/2025"},{"key":"Phường mới","value":"Bình An + Bình Thắng + Đông Hòa → phường Đông Hòa, TP.HCM"},{"key":"Quy mô phường","value":"21,893 km² · 132.056 dân · trụ sở 153 QL1K"},{"key":"Bối cảnh lớn","value":"Bình Dương + BR-VT + TP.HCM hợp nhất; TP.HCM mới có 113 phường"},{"key":"Hiệu lực hồ sơ cũ","value":"Văn bản cấp thời Bình Dương vẫn còn hiệu lực"}]'::jsonb,'"Việc sáp nhập đã hoàn tất từ 1/7/2025 — dự án nay thuộc TP.HCM, nâng định vị từ BĐS vệ tinh thành nội đô. Toàn bộ pháp lý gốc vẫn hiệu lực, chỉ thay cách ghi địa chỉ."','Sự kiện hành chính lớn nhất ảnh hưởng đến cách định vị dự án: từ "căn hộ Bình Dương giáp TP.HCM" thành "căn hộ TP.HCM" đúng nghĩa pháp lý. Hồ sơ pháp lý gốc cấp dưới thời Bình Dương vẫn hiệu lực, chỉ cập nhật cách ghi địa chỉ trên hợp đồng, hóa đơn, sổ hồng.',12),
  ('3e669843-ce3e-5c06-b4fb-6ac42241180a','00000000-0000-0000-0000-00000000b005','master-5-thap','Quy hoạch 5 tháp','product',null,'[{"key":"Cấu trúc","value":"2 tháp thương mại + 3 tháp căn hộ"},{"key":"The Twin","value":"2 tòa tháp đôi cao 36 tầng"},{"key":"The Gateway","value":"29 tầng · 812 căn"},{"key":"The Icon","value":"29 tầng · 549 căn"},{"key":"The Crown","value":"29 tầng · 579 căn"},{"key":"Tổng căn","value":"1.940 căn"},{"key":"Quỹ đất","value":"3,2 ha / 32.000 m²"}]'::jsonb,'"Cách nhớ nhanh: 2 tháp thương mại The Twin + 3 tháp căn hộ Gateway, Icon, Crown. Đây là khung để dẫn khách qua toàn bộ masterplan."','Khung masterplan dễ đào tạo: 2 tháp thương mại The Twin + 3 tháp căn hộ Gateway, Icon, Crown. Đây là khung để sales dẫn khách đi qua toàn bộ dự án theo đúng thứ tự.',13),
  ('b2dc8360-cef9-526c-a458-7a12118655c5','00000000-0000-0000-0000-00000000b005','the-twin','The Twin','product',null,'[{"key":"Loại","value":"2 tòa tháp đôi thương mại"},{"key":"Chiều cao","value":"36 tầng"},{"key":"Khối đế TTTM","value":"7 tầng · tổng sàn ~48.000 m²"},{"key":"Rạp chiếu phim","value":"Tầng 4–5"},{"key":"Hồ bơi vô cực","value":"Tầng 7"},{"key":"Hồ bơi ốc đảo","value":"Trước mặt The Twin"}]'::jsonb,'"The Twin là node tạo khác biệt. Khi khách hỏi dự án có gì hơn một chung cư thường, hãy dẫn vào 7 tầng TTTM, rạp chiếu phim và hồ bơi vô cực."','The Twin là cụm tháp đôi thương mại — điểm nhấn nhận diện và trung tâm tiện ích của dự án: khối đế TTTM 7 tầng ~48.000 m² sàn, rạp phim tầng 4–5, hồ bơi vô cực tầng 7 và hồ ốc đảo phía trước.',14),
  ('1d707be4-87f1-5698-9fe9-732c2186456d','00000000-0000-0000-0000-00000000b005','the-gateway','The Gateway','product',null,'[{"key":"Loại","value":"Tháp căn hộ · 29 tầng"},{"key":"Số căn","value":"812 căn"},{"key":"View Đông Nam","value":"Hồ Bình An, KDL Thủy Châu, sông Đồng Nai"},{"key":"View Tây Nam","value":"Bcons City, Làng Đại học, Hồ đá, Landmark 81"},{"key":"Layout","value":"1PN, 2PN, 3PN"}]'::jsonb,'"Với The Gateway, đừng chỉ nói số căn. Đông Nam cho khách thích thiên nhiên mặt nước; Tây Nam cho khách thích nhìn đô thị và skyline — chọn hướng theo tính cách khách."','Tháp căn hộ có dữ liệu đầy đủ nhất. Công cụ tư vấn mạnh nhất là câu chuyện hai hướng view: Đông Nam thiên nhiên mặt nước — Tây Nam đô thị, làng đại học và skyline Landmark 81. Khi hai căn cùng diện tích, hướng nhìn thường là lý do khiến khách xuống tiền.',15),
  ('094429e5-4318-5f8c-9f0e-6f229acdceba','00000000-0000-0000-0000-00000000b005','the-icon','The Icon','product',null,'[{"key":"Loại","value":"Tháp căn hộ · 29 tầng"},{"key":"Số căn","value":"549 căn"},{"key":"Cần bổ sung","value":"Hướng view, layout chi tiết, số căn mỗi tầng"}]'::jsonb,null,'Một trong ba tháp căn hộ 29 tầng — Q&A xác nhận 549 căn. Node giữ riêng để khi mở bán theo block, đội sales cập nhật inventory đúng chỗ mà không làm rối toàn map.',16),
  ('b74c8141-aaf7-5e29-bba9-27d71d4e16d8','00000000-0000-0000-0000-00000000b005','the-crown','The Crown','product',null,'[{"key":"Loại","value":"Tháp căn hộ · 29 tầng"},{"key":"Số căn","value":"579 căn"},{"key":"Cần bổ sung","value":"Hướng view, layout chi tiết, inventory"}]'::jsonb,null,'Tháp căn hộ 29 tầng với 579 căn theo Q&A. Tên "Crown" có thể dùng định vị nhóm khách muốn cảm giác cao cấp hơn — nhưng mọi claim phải đi theo dữ liệu thật khi có bảng hàng.',17),
  ('e9a32686-c0a3-588a-bea5-95d03f4b269c','00000000-0000-0000-0000-00000000b005','co-cau-can','Cơ cấu căn 1–3PN','product',null,'[{"key":"1PN","value":"43,59 – 45,48 m²"},{"key":"2PN","value":"52,48 – 59,15 m²"},{"key":"3PN","value":"85,83 m²"},{"key":"Tệp khách","value":"Người trẻ, gia đình nhỏ, ở thật, đầu tư cho thuê"}]'::jsonb,'"Bắt đầu bằng nhu cầu ở: độc thân, cặp đôi, gia đình trẻ, hay cho thuê. Sau đó mới vào block, tầng, view và chính sách."','Dải diện tích công bố chính thức. Quy trình tư vấn đúng: bắt đầu bằng nhu cầu ở (độc thân, cặp đôi, gia đình trẻ, cho thuê) rồi mới vào block, tầng, view và chính sách.',18),
  ('8b372a48-5019-542b-81c7-1fe5509577b1','00000000-0000-0000-0000-00000000b005','ham-lech-tang','Tầng hầm lệch tầng','product',null,'[{"key":"Cấu trúc","value":"Hầm lệch tầng giữa khu TMDV và khu chung cư"},{"key":"Liên thông","value":"Hầm B1 khu TMDV giao với hầm B2 khu chung cư"},{"key":"Chiều cao B1","value":"4 m"},{"key":"Chiều cao B2","value":"3 m"}]'::jsonb,null,'Chi tiết kỹ thuật đáng giá khi khách hỏi về vận hành, đậu xe và lưu thông giữa khu thương mại với khu căn hộ — cấu trúc hầm lệch tầng khác hẳn hầm phẳng thông thường.',19),
  ('32d49010-0b2b-53e8-b58c-fc8d7dd978f1','00000000-0000-0000-0000-00000000b005','gia-chinh-sach','Giá & chính sách bán','product','⚠ Time-sensitive — chỉ dùng bảng giá theo ngày hiệu lực','[{"key":"Giá rumor","value":"~55 triệu/m² (chưa VAT) — chưa phải giá niêm yết chính thức"},{"key":"Căn 2PN tham khảo","value":"~2,9 tỷ (đã gồm VAT 10%)"},{"key":"Booking sales page","value":"5% / ~150 triệu chia 2 đợt"},{"key":"Ưu đãi sales page","value":"VCB 0% lãi 18 tháng (cần văn bản hiệu lực)"},{"key":"CĐT định vị","value":"Thấp hơn mặt bằng Dĩ An–Thủ Đức 65–75 triệu/m²"},{"key":"Quy tắc","value":"Luôn mở bảng giá mới nhất: tháp, tầng, view, thông thủy/tim tường"}]'::jsonb,'"Con số 130–150 triệu là thanh toán đợt đầu theo tiến độ, không phải giá căn. Tổng giá trị căn 2PN khoảng 2,9 tỷ đã gồm VAT — em luôn báo tổng giá trước để Anh/Chị tính dòng tiền chính xác."','Nhóm dữ liệu nhạy cảm nhất, biến động theo tháng. Giá ~55 triệu/m² là rumor/sales page, chưa phải bảng giá ký phát hành. Cảnh báo truyền thông: con số "130–150 triệu sở hữu" là thanh toán đợt đầu 5%, không phải giá căn.',20),
  ('b0f2e11b-5ec2-5ce6-b201-8ba66abe749a','00000000-0000-0000-0000-00000000b005','ban-giao','Bàn giao Q4/2027','product','⚠ Dự kiến — cần ảnh tiến độ theo tháng','[{"key":"Bàn giao dự kiến","value":"Quý IV/2027"},{"key":"Khởi công","value":"28/6/2025 (ngay sau GPXD 27/6/2025)"},{"key":"Nguồn","value":"Bcons official + sales page"},{"key":"Cần theo dõi","value":"Tiến độ thi công, ảnh site, thông báo CĐT"}]'::jsonb,null,'Mốc bàn giao luôn đi kèm chữ dự kiến. Timeline bán hàng tốt nhất là timeline có ảnh tiến độ công trường cập nhật theo tháng — nếu chỉ nói Q4/2027 mà không có ảnh, khách sẽ xem đó là lời hứa.',21),
  ('45dde71e-4680-5e07-917b-0d26f9a37a0a','00000000-0000-0000-0000-00000000b005','cho-thue','Cầu thuê & lợi suất','product',null,'[{"key":"Tham chiếu thuê Bcons City","value":"2PN ~5,5–8,5 triệu/tháng · 1PN ~4,5–6,5 triệu/tháng"},{"key":"Lợi suất gộp ước tính","value":"~4–5%/năm"},{"key":"Tệp thuê thật","value":"Giảng viên, chuyên gia, nhân viên KCN, SV ở ghép ngân sách 5–7 triệu"},{"key":"Lưu ý","value":"Không nói \"90.000 sinh viên đều là khách thuê căn hộ\""}]'::jsonb,'"Lợi suất gộp quanh 4–5%/năm dựa trên giá thuê thật khu này — em không hứa cao hơn, vì con số thật mới giữ được uy tín khi Anh/Chị nhận nhà và cho thuê thực tế."','Giá thuê thật tại Bcons City đã bàn giao là tham chiếu trực tiếp cho Center City. Phân tầng tệp thuê cho đúng: sinh viên KTX giá 200 nghìn không phải khách thuê căn hộ — khách thuê thật là giảng viên, chuyên gia, nhân viên KCN và nhóm SV ở ghép.',22),
  ('15fbad8d-6aea-5204-8a05-166f4f360fba','00000000-0000-0000-0000-00000000b005','tien-ich-74','74 tiện ích nội khu','amenity',null,'[{"key":"Bcons Center City","value":"74 tiện ích"},{"key":"Bcons City đối diện","value":"135 tiện ích"},{"key":"Nhóm tiện ích","value":"TTTM, rạp phim, hồ bơi, quảng trường, nhạc nước, trường học, F&B, gym, trẻ em"},{"key":"Kết nối","value":"Cầu đi bộ qua Thống Nhất 32m"}]'::jsonb,'"Đừng kể 74 tiện ích như đọc danh sách. Gom thành 4 cụm: mua sắm, giải trí, nghỉ dưỡng và giáo dục. Khách nhớ cụm giá trị, không nhớ số lượng."','74 tiện ích nội khu + khả năng tiếp cận 135 tiện ích Bcons City qua cầu đi bộ — đây là node mạnh nhất để nói về hệ sinh thái thay vì tiện ích đơn dự án.',23),
  ('66e76f32-a7e6-59c2-9985-1bab0d39c963','00000000-0000-0000-0000-00000000b005','tttm-7-tang','TTTM 7 tầng','amenity',null,'[{"key":"Vị trí","value":"Khối đế The Twin"},{"key":"Quy mô","value":"7 tầng · ~48.000 m² sàn"},{"key":"Chức năng","value":"Mua sắm, F&B, giải trí, dịch vụ, rạp phim"}]'::jsonb,null,'Khối thương mại quy mô lớn hiếm có ở phân khúc tầm trung — chuyển câu chuyện từ "căn hộ" sang "khu phức hợp", tăng tính ở thật và thanh khoản cho thuê.',24),
  ('e6d2aca7-dd59-5e95-9237-9cf95210cd8a','00000000-0000-0000-0000-00000000b005','rap-phim','Rạp chiếu phim','amenity',null,'[{"key":"Vị trí","value":"Tầng 4–5 The Twin"},{"key":"Điểm mới","value":"Lần đầu xuất hiện trong các dự án Bcons"},{"key":"Vai trò sales","value":"Điểm giải trí khác biệt, kéo traffic thương mại"}]'::jsonb,'"Một câu ngắn đủ mạnh: Cuối tuần không cần ra khỏi khu — lên The Twin xem phim là xong."','Tiện ích lần đầu có trong hệ Bcons — dễ nhớ, dễ kể, có sức gợi hình trong sales script.',25),
  ('85740a43-4e8d-58be-85db-ef1f0cc45a3a','00000000-0000-0000-0000-00000000b005','quang-truong','Công viên quảng trường','amenity',null,'[{"key":"Diện tích","value":"Lên đến 8.000 m²"},{"key":"Thiết kế","value":"Cảnh quan đa tầng"},{"key":"Điểm nhấn","value":"Nhạc nước đa sắc"}]'::jsonb,null,'Quảng trường 8.000 m² là không gian cộng đồng — nơi trẻ em chơi, gia đình đi dạo, cư dân tụ họp. Yếu tố làm dự án có đời sống sau bàn giao, không chỉ là tiện ích đẹp trong phối cảnh.',26),
  ('1aaa3c1e-0058-5002-8406-a9d392b13045','00000000-0000-0000-0000-00000000b005','ho-boi','2 hồ bơi','amenity',null,'[{"key":"Hồ bơi 1","value":"Hồ vô cực — tầng 7 The Twin"},{"key":"Hồ bơi 2","value":"Hồ ốc đảo — trước mặt The Twin"}]'::jsonb,null,'Hai hồ bơi ở hai lớp không gian — tầng 7 và mặt đất. "Một hồ bơi là tiện ích; hai hồ bơi ở hai cao độ là câu chuyện lifestyle."',27),
  ('010395fa-1f78-5b21-ba91-cd5b469b117d','00000000-0000-0000-0000-00000000b005','cau-di-bo','Cầu đi bộ Bcons City','amenity',null,'[{"key":"Kết nối","value":"Bcons Center City ↔ Bcons City"},{"key":"Vượt qua","value":"Đường Thống Nhất lộ giới 32m"},{"key":"Ý nghĩa","value":"Mở rộng tiện ích dùng chung 74 + 135 tiện ích"}]'::jsonb,'"Cầu đi bộ là bằng chứng vật lý của hệ sinh thái. Có cầu nghĩa là cư dân không chỉ sống trong một dự án, mà sống trong một cụm Bcons."','Chi tiết nhỏ nhưng sức nặng chiến lược: biến câu chuyện từ "một dự án có 74 tiện ích" thành "một cụm đô thị Bcons với hệ tiện ích mở rộng".',28),
  ('f5c6ef8b-8cc1-5415-b84d-da9edd5a6fdd','00000000-0000-0000-0000-00000000b005','metro-1','Metro Line 1','metro',null,'[{"key":"Tuyến","value":"Bến Thành – Suối Tiên · 19,7 km · 14 ga"},{"key":"Vận hành","value":"22/12/2024"},{"key":"Ga gần dự án","value":"Suối Tiên / Bến xe Miền Đông mới — vài phút BẰNG XE"},{"key":"Tham chiếu","value":"Bcons City cách ga Suối Tiên ~1,5 km"},{"key":"Tương lai","value":"Metro 1 nối dài (Long Thành / Bình Dương) — định hướng 2026–2030, chưa khởi công"}]'::jsonb,'"Metro 1 đã chạy thật mỗi ngày — khác biệt với các câu chuyện hạ tầng còn nằm trên quy hoạch. Nhưng em nói chính xác: ga gần nhất đi xe vài phút, không phải đi bộ."','Driver hạ tầng đã hiện hữu — không bán như lời hứa. Lưu ý truyền thông: CĐT nói "2 phút tới Metro" — phải nói rõ là vài phút bằng xe máy/ô tô, không phải đi bộ.',29),
  ('3399a9c7-211b-55da-b9b2-ce937f068aa1','00000000-0000-0000-0000-00000000b005','bxmd','Bến xe Miền Đông mới','metro','⚠ Số phút di chuyển cần đo theo tuyến thực tế','[{"key":"Vai trò","value":"Hub liên vùng khu Đông + kết nối Metro Line 1"},{"key":"Nguồn dự án","value":"Bcons official ghi ~10 phút"},{"key":"Cần kiểm tra","value":"Thời gian thực tế giờ cao điểm / thấp điểm"}]'::jsonb,null,'Hub liên vùng quan trọng trong câu chuyện kết nối — nhưng các mốc "phút di chuyển" nên đo lại theo tuyến thực thay vì quote cố định.',30),
  ('8f0df27e-1b86-586d-87b6-e286d93a6363','00000000-0000-0000-0000-00000000b005','thong-nhat','Đường Thống Nhất 32m','road',null,'[{"key":"Vai trò","value":"Trục định vị khu vực của dự án"},{"key":"Lộ giới","value":"32 m"},{"key":"Chi tiết Q&A","value":"Cầu đi bộ bắc ngang nối sang Bcons City"}]'::jsonb,'"Đừng chỉ nói gần Bcons City. Hãy nói có kết nối bằng cầu đi bộ qua đường Thống Nhất 32m — đó là bằng chứng hệ sinh thái, không phải lời kể."','Trục định vị mạnh của dự án — đại lộ Đông-Tây của khu Dĩ An cũ. Kết hợp với cầu đi bộ, Thống Nhất 32m trở thành "trục xương sống" của cụm Bcons.',31),
  ('7f06a10e-457e-53ce-902a-cf4d8cc19bfc','00000000-0000-0000-0000-00000000b005','d11','Đường D11','road','⚠ Hiện hữu 7m · quy hoạch 17m — cần bản vẽ','[{"key":"Hiện hữu","value":"7 m"},{"key":"Quy hoạch mở rộng","value":"17 m (vài nguồn ghi 21m)"},{"key":"Vai trò","value":"Đường tiếp cận trực tiếp của dự án"}]'::jsonb,'"D11 là câu chuyện tiếp cận thực tế, Thống Nhất là câu chuyện trục khu vực. Em phân biệt rõ để Anh/Chị hình dung đúng hiện trạng hôm nay và quy hoạch ngày mai."','D11 là trục tiếp cận thực tế; Thống Nhất là trục khu vực — phải phân biệt hai lớp này để không làm khách hiểu sai về mặt tiền. Trạng thái partial: cần kiểm tra bản vẽ quy hoạch mở rộng.',32),
  ('95489256-d754-5076-a6a7-7883613709b2','00000000-0000-0000-0000-00000000b005','vanh-dai-3','Vành đai 3','road',null,'[{"key":"Toàn tuyến","value":"76,3 km · vốn hơn 75.000 tỷ đồng"},{"key":"Kết nối","value":"TP.HCM – Bình Dương cũ – Đồng Nai – Long An"},{"key":"Mốc gần dự án","value":"Thông xe kỹ thuật đoạn phía Đông ~15 km khoảng 30/6/2026"},{"key":"Mục tiêu","value":"Hoàn thành toàn bộ trong năm 2026"}]'::jsonb,null,'Driver kết nối vùng lớn nhất của cửa ngõ Đông. Tư vấn đúng kỳ vọng: upside vùng, không phải tiện ích nội khu — và timeline từng đoạn có thể xê dịch.',33),
  ('dfb94019-4db3-557b-8f28-3399e4bf40bc','00000000-0000-0000-0000-00000000b005','tan-van','Nút giao Tân Vạn','road',null,'[{"key":"Gói thầu","value":"XL1 · ~1.832 tỷ đồng · dài 2,48 km"},{"key":"Thiết kế","value":"3 tầng lưu thông · 5 nhánh cầu vượt"},{"key":"Khởi công","value":"31/5/2024"},{"key":"Tiến độ","value":">60% khối lượng (cuối 10/2025)"},{"key":"Thông xe kỹ thuật","value":"Khoảng 30/6/2026 cùng đoạn phía Đông VĐ3"}]'::jsonb,'"Chỗ kẹt xe Anh/Chị ngán nhất ở Tân Vạn chính là nơi đang đổ gần 2.000 tỷ để gỡ — và mốc thông xe kỹ thuật chỉ còn tính bằng tháng."','Nút giao 3 tầng thuộc Vành đai 3 — điểm nghẽn lịch sử của cụm Tân Vạn/QL1A đang được gỡ. Trong lúc thi công gây kẹt tạm thời; sau 6/2026 là cú nâng hạ tầng trực tiếp cho toàn khu Đông Hòa.',34),
  ('85c16b85-1f50-59be-8e81-f78162a21ec2','00000000-0000-0000-0000-00000000b005','ql1k-xlhn','Trục QL1K / QL1A / XLHN','road',null,'[{"key":"Các trục","value":"QL1K, QL1A, Xa lộ Hà Nội (Võ Nguyên Giáp), DT743, Phạm Văn Đồng"},{"key":"Hiện trạng","value":"Ùn tắc giờ cao điểm, nặng hơn khi thi công nút Tân Vạn"},{"key":"Triển vọng","value":"Giảm tải khi VĐ3 + nút Tân Vạn thông xe 2026"}]'::jsonb,null,'Mạng trục hiện hữu quanh dự án — vừa là lợi thế kết nối đa hướng, vừa là điểm trừ kẹt xe cần nói thật với khách (xem node rủi ro mật độ).',35),
  ('f6691baa-b5d1-5f67-828c-3b50480e8280','00000000-0000-0000-0000-00000000b005','dong-hoa','Đông Hòa / Dĩ An cũ','location',null,'[{"key":"Địa chỉ public","value":"Đường Thống Nhất, phường Đông Hòa, TP.HCM"},{"key":"Nhãn sales cũ","value":"Dĩ An / Bình Dương"},{"key":"Nhãn nên dùng","value":"Đông Hòa, TP.HCM — khu Dĩ An cũ"},{"key":"Lợi thế vị trí","value":"Sát Thủ Đức, ĐHQG, Metro, Bến xe Miền Đông mới"}]'::jsonb,'"Nói ''Đông Hòa, TP.HCM — khu Dĩ An cũ'' là cách an toàn nhất: đúng hành chính mới, vẫn giữ được nhận diện thị trường."','Trình bày bằng 2 lớp nhãn: hành chính mới là Đông Hòa, TP.HCM, ngôn ngữ thị trường quen là Dĩ An cũ. Cách ghi song song giúp khách không mất định vị khu vực mà hồ sơ vẫn chuẩn.',36),
  ('45efef57-4f1a-52d2-848b-6de03e0938df','00000000-0000-0000-0000-00000000b005','lang-dai-hoc','ĐHQG TP.HCM','location',null,'[{"key":"Quy mô","value":"Hơn 90.000 sinh viên theo học"},{"key":"KTX lớn nhất VN","value":"47 tòa · 42,08 ha · 6.695 phòng · phục vụ 28 trường"},{"key":"Năm 2024–2025","value":"~35.500 SV ở KTX (25.000 cũ + 10.500 tân SV)"},{"key":"Giá KTX","value":"205.000đ – 2,815 triệu/tháng"},{"key":"Khoảng cách sales claim","value":"~5 phút (cần đo tuyến thực)"}]'::jsonb,'"ĐHQG tạo cầu thuê thật — nhưng phải phân tầng: sinh viên thuê khác, giảng viên thuê khác, chuyên gia trẻ thuê khác. Nói đúng tệp thì lời hứa lợi suất mới đứng vững."','Nguồn cầu ở thật và cầu thuê quan trọng nhất của khu vực. Phân tầng đúng: KTX phục vụ sinh viên ngân sách thấp; khách thuê căn hộ là giảng viên, chuyên gia trẻ, nhân sự khu công nghệ và nhóm SV ở ghép ngân sách cao hơn.',37),
  ('dc9e9679-64d9-5117-80cf-3d3b39229d4a','00000000-0000-0000-0000-00000000b005','kcn-tien-ich','KCN & tiện ích khu vực','location',null,'[{"key":"Khu công nghiệp","value":"Sóng Thần, Linh Trung, VSIP — nguồn cầu nhân sự"},{"key":"Thương mại","value":"GO! Dĩ An, Vincom Dĩ An"},{"key":"Y tế","value":"Bệnh viện Quốc tế Hoàn Mỹ"},{"key":"Khác","value":"KDL Suối Tiên, công viên Dĩ An, trường BSchool nội khu Bcons"}]'::jsonb,null,'Vành đai tiện ích và việc làm hiện hữu quanh dự án — nền của cầu ở thật: công nhân viên KCN, kỹ sư, giảng viên và gia đình trẻ làm việc trong bán kính 15 phút.',38),
  ('9a92b841-e573-585e-822f-334fa066d87a','00000000-0000-0000-0000-00000000b005','bcons-city','Bcons City','comparable','Đối diện — benchmark hệ sinh thái quan trọng nhất','[{"key":"Quy mô","value":"KDC 12 ha · 5 tháp · ~3.900 căn · 135 tiện ích"},{"key":"Bàn giao","value":"4 tháp (Topaz, Emerald, Sapphire, Bcons City) 10/2025"},{"key":"Tháp còn lại","value":"Green Diamond — dự kiến Q1/2027"},{"key":"Thứ cấp 2PN","value":"~2,4 – 2,65 tỷ (gồm VAT) · tháp Diamond ~46 triệu/m²"},{"key":"Giá thuê","value":"2PN ~5,5–8,5 triệu/tháng · 1PN ~4,5–6,5 triệu/tháng"},{"key":"Hợp tác","value":"Tháp thuộc KDC có A Asset (Thái Lan) tham gia"}]'::jsonb,'"Benchmark tốt nhất của Center City không phải dự án nào xa lạ — chính là Bcons City đối diện: thứ cấp 2,4–2,65 tỷ, thuê 5,5–8,5 triệu. Đó là số thật để Anh/Chị tự định giá Center City."','Benchmark thực tế nhất cho Center City: cùng CĐT, đối diện qua đường Thống Nhất, đã có cư dân thật, giá thuê thật và giao dịch thứ cấp thật. Kết nối bằng cầu đi bộ biến hai dự án thành một cụm 74 + 135 tiện ích.',39),
  ('1730713e-282a-5101-a0b2-87c01bf8573a','00000000-0000-0000-0000-00000000b005','bcons-garden','Bcons Garden','comparable','⚠ Đang có tranh chấp vận hành 2026 — xem node rủi ro','[{"key":"Vị trí","value":"25A Phạm Hữu Lầu, P. Dĩ An"},{"key":"Quy mô","value":"Hơn 1.800 căn · 4 tháp"},{"key":"Trạng thái","value":"Đã bàn giao, đang vận hành"},{"key":"Vấn đề 2026","value":"Tranh chấp quỹ bảo trì & hợp đồng vận hành (cư dân vs BQT)"}]'::jsonb,null,'Dự án Bcons đã bàn giao với hơn 1.800 căn — hiện là điểm nóng truyền thông 3–5/2026 về quỹ bảo trì và hợp đồng vận hành. Khách tra Google "Bcons" sẽ gặp vụ này đầu tiên, nên sale phải nắm chi tiết tại node rủi ro để chủ động trả lời.',40),
  ('8a7d9d3f-0f42-5e5d-b845-f396b61d863d','00000000-0000-0000-0000-00000000b005','bcons-others','Các dự án Bcons khác','comparable',null,'[{"key":"Bcons Suối Tiên","value":"653 căn — đã bàn giao"},{"key":"Bcons Miền Đông","value":"768 căn — đã bàn giao"},{"key":"Khác","value":"Green View, Plaza, Bee, Sala, Polaris, Polygon, Solary, Asahi"},{"key":"Vai trò","value":"Benchmark giá, hấp thụ, khai thác cho thuê của hệ Bcons"}]'::jsonb,null,'Chuỗi dự án đã bàn giao quanh làng đại học — bằng chứng năng lực triển khai liên tục của Bcons ở phân khúc vừa túi tiền, đồng thời là nguồn dữ liệu thứ cấp/cho thuê để đối chiếu khi tư vấn Center City.',41),
  ('1f5cff8a-d06a-5bd4-a3e6-48720c31e1d4','00000000-0000-0000-0000-00000000b005','phu-dong','Phú Đông SkyOne','comparable',null,'[{"key":"CĐT","value":"Phú Đông Group (Cty Đầu tư Phú Đông 5)"},{"key":"Vị trí","value":"DT743C, Tân Đông Hiệp / Dĩ An cũ"},{"key":"Quy mô","value":"~780 căn · 2 block 30–31 tầng"},{"key":"Pháp lý","value":"GPXD 4273/GPXD 30/11/2023 · CT đầu tư 841/QĐ-UBND 24/3/2025"},{"key":"Giá","value":"~28,6 – 40,2 triệu/m² · bảo lãnh MB Bank"},{"key":"Bàn giao","value":"Q2/2026"}]'::jsonb,null,'Đối thủ giá rẻ hơn trong khu — vũ khí của khách khi ép giá ("sao Bcons đắt hơn Phú Đông?"). Trả lời bằng khác biệt sản phẩm: khu phức hợp 5 tháp + TTTM 7 tầng + cụm hệ sinh thái, so với dự án 2 block thuần ở.',42),
  ('b768014f-8116-5a3a-99cc-81c9e0b6babc','00000000-0000-0000-0000-00000000b005','picity','Picity Sky Park','comparable',null,'[{"key":"CĐT","value":"Pi Group / Cty Khách sạn Đầu tư Kim Sơn"},{"key":"Vị trí","value":"QL1A, P. An Bình / Dĩ An cũ"},{"key":"Quy mô","value":"~1.567 sản phẩm · 3 tháp đến 40 tầng"},{"key":"Pháp lý","value":"CT 3009/QĐ-UBND 18/11/2022 · 1/500 QĐ 2341 16/6/2023"},{"key":"Giá","value":"~40 – 50 triệu/m²"},{"key":"Bàn giao","value":"Q4/2026"}]'::jsonb,null,'Đối thủ cùng dải giá sát nhất với Center City (40–50 vs ~55 triệu/m² rumor) — so găng trực tiếp về vị trí tiếp cận, tiện ích khối đế và uy tín bàn giao.',43),
  ('d209ab5d-2991-5366-aada-7595e52cd948','00000000-0000-0000-0000-00000000b005','tt-avio','TT AVIO','comparable',null,'[{"key":"CĐT","value":"TT Capital × Cosmos Initia (Nhật) — qua Cty CP Đầu tư Phúc Lộc Khang"},{"key":"Vị trí","value":"DT743C, Dĩ An cũ"},{"key":"Giá","value":"Từ ~1,1 tỷ/căn · PTTT ~9 triệu/tháng"},{"key":"Tiến độ","value":"Ký HĐMB dự kiến Q3/2026"}]'::jsonb,null,'Đối thủ chơi bài "chuẩn Nhật + thanh toán nhẹ" — hút tệp khách trẻ lần đầu mua nhà. Phản công bằng quy mô phức hợp và hệ tiện ích cụm Bcons mà dự án đơn lẻ không có.',44),
  ('df4fa56f-7aac-5a30-aaea-a8e25308eecf','00000000-0000-0000-0000-00000000b005','la-pura','La Pura','comparable',null,'[{"key":"CĐT","value":"Phát Đạt (PDR) — tên cũ Astral City"},{"key":"Vị trí","value":"QL13, Thuận An / P. Bình Hòa"},{"key":"Quy mô","value":"8 block 40 tầng · ~6.000 căn"},{"key":"Pháp lý","value":"GPXD 3817/GPXD · đủ ĐK huy động vốn 24/7/2023"},{"key":"Giá","value":"~39,5 – 72,7 triệu/m²"},{"key":"Bàn giao","value":"2026–2028"}]'::jsonb,null,'Nguồn cung lớn phía trục QL13 (Bình Dương cũ) — cạnh tranh hút khách đầu tư diện rộng. Dải giá trải dài 39,5–72,7 triệu/m² cho thấy mặt bằng "TP.HCM mới" đang định hình lại toàn khu.',45),
  ('bf86fd69-d749-558b-bb21-51a972b145ea','00000000-0000-0000-0000-00000000b005','di-an-market','Mặt bằng giá Dĩ An/Đông Hòa','comparable',null,'[{"key":"Sơ cấp phổ biến","value":"~33 – 55 triệu/m² (2024–2026)"},{"key":"Center City rumor","value":"~55 triệu/m² (chưa VAT)"},{"key":"CĐT so sánh","value":"Dĩ An – Thủ Đức lân cận 65 – 75 triệu/m²"},{"key":"Giá thuê khu vực","value":"2PN ~5,5 – 9 triệu/tháng"}]'::jsonb,null,'Khung định vị giá: Center City rumor nằm ở đỉnh dải giá Dĩ An cũ nhưng dưới mặt bằng Thủ Đức lân cận. Câu chuyện "mua TP.HCM giá Dĩ An" chỉ đứng vững nếu chứng minh được khác biệt sản phẩm phức hợp.',46),
  ('25ed6628-ca67-5ddb-88a0-dfa725bcb642','00000000-0000-0000-0000-00000000b005','risk-garden-2026','Tranh chấp Bcons Garden 2026','risk','⚠ Đang diễn tiến — nguồn: loạt bài Phụ Nữ Online 3–5/2026','[{"key":"Diễn biến","value":"Cư dân treo băng rôn, ký đơn 22/3/2026 đòi hội nghị bất thường"},{"key":"Quỹ bảo trì","value":"Gốc 44,48 tỷ gửi MBBank lãi 0,2%/năm (kỳ hạn 1 tuần, từ 23/2/2022)"},{"key":"Lãi đến 10/4/2026","value":"~348,7 triệu — cư dân cho là thấp bất thường"},{"key":"HĐ vận hành 11/2/2026","value":"BQT ký với Bcons Service: 50% doanh thu sở hữu chung + tự thu-chi giữ xe"},{"key":"Phí quản lý","value":"7.000đ/m² — chưa thông qua hội nghị cư dân"},{"key":"Diễn biến chính quyền","value":"Họp 21/4/2026: BQT có 30 ngày khắc phục, sau đó lấy tín nhiệm online"},{"key":"Bản chất","value":"Tranh chấp cư dân ↔ Ban Quản trị (do cư dân bầu), chưa có kết luận cơ quan chức năng"}]'::jsonb,'"Vụ Bcons Garden chủ yếu là tranh chấp giữa cư dân và Ban Quản trị do chính cư dân bầu, về quỹ bảo trì và doanh thu khai thác — không phải lỗi kết cấu xây dựng. Bài học thật cho Anh/Chị: tham gia đầy đủ hội nghị nhà chung cư và yêu cầu minh bạch sao kê quỹ bảo trì ngay từ đầu."','Vụ việc khách dễ gặp nhất khi Google "Bcons": tranh chấp tại Bcons Garden về quỹ bảo trì 44,48 tỷ và hợp đồng vận hành ký với Bcons Service. Bản chất pháp lý: mâu thuẫn giữa cư dân và Ban Quản trị — nhưng vì đơn vị vận hành thuộc hệ Bcons nên uy tín thương hiệu bị ảnh hưởng trực tiếp. Quy tắc: không né, không đổ lỗi cư dân, không bịa kết luận khi vụ việc chưa kết thúc.',47),
  ('c4e62de9-abff-578a-aab9-ca1487832789','00000000-0000-0000-0000-00000000b005','risk-booking','Booking trước đủ ĐK bán','risk','⚠ Rủi ro pháp lý số 1 ở giai đoạn hiện tại','[{"key":"Hiện trạng","value":"Nhận giữ chỗ khi chưa thấy văn bản đủ điều kiện bán"},{"key":"Tính chất booking","value":"Thỏa thuận dân sự, hoàn lại được — KHÔNG phải HĐMB"},{"key":"Mốc chuyển trạng thái","value":"Văn bản Sở Xây dựng + ký HĐMB (~7/2026)"},{"key":"Hành vi cấm","value":"Mô tả booking như \"đã mở bán chính thức\""}]'::jsonb,null,'Mọi dự án nhận booking sớm đều mang rủi ro này — khác biệt nằm ở cách nói. Sale nói thẳng tính chất pháp lý của giữ chỗ sẽ giữ được cả khách lẫn uy tín khi dự án chuyển sang giai đoạn HĐMB.',48),
  ('8046395c-0a4d-5688-b928-14c239325f10','00000000-0000-0000-0000-00000000b005','risk-density','Mật độ cụm Bcons & hạ tầng','risk',null,'[{"key":"Quy mô cụm","value":"Bcons City ~3.900 + Center City ~1.940 + Garden >1.800 căn + nhiều dự án khác"},{"key":"Áp lực","value":"Giao thông Thống Nhất/QL1K, trường học, y tế khu Đông Hòa"},{"key":"Mật độ XD Center City","value":"CĐT công bố dưới 40%"},{"key":"Đối trọng","value":"VĐ3 + nút Tân Vạn thông xe 2026 kỳ vọng giải tỏa"}]'::jsonb,'"Mật độ cụm này cao là thật — bù lại là hệ tiện ích cụm và hạ tầng 2026. Nếu Anh/Chị ưu tiên thưa vắng, em sẽ nói thật đây không phải lựa chọn phù hợp; còn nếu ưu tiên tiện ích và cho thuê thì mật độ chính là dòng khách thuê."','Mật độ dân cư cụm Bcons quanh làng đại học là thực tế phải thừa nhận, không tô hồng. Đối trọng là chuỗi hạ tầng 2026; nhưng nếu khách ưu tiên không gian thưa, thấp tầng — đây là điểm cần nói thẳng để lọc đúng tệp.',49),
  ('4337579f-6e0e-5871-a164-79590f4f14bf','00000000-0000-0000-0000-00000000b005','risk-pricing-comms','Truyền thông giá & khoảng cách','risk',null,'[{"key":"\"130–150 triệu sở hữu\"","value":"Là thanh toán đợt đầu 5%, KHÔNG phải giá căn"},{"key":"\"2 phút tới Metro\"","value":"Là vài phút BẰNG XE, không phải đi bộ"},{"key":"\"5 phút tới ĐHQG\"","value":"Sales claim — cần đo tuyến thực"},{"key":"Quy tắc","value":"Luôn nói tổng giá trị căn + phương tiện di chuyển cụ thể"}]'::jsonb,null,'Hai chiêu truyền thông dễ gây hiểu lầm nhất của phân khúc này: con số thanh toán đợt đầu bị đọc thành giá căn, và số phút di chuyển bị hiểu thành đi bộ. Sale chỉnh lại ngay từ đầu sẽ tránh được khiếu nại về sau.',50),
  ('fdfff225-5337-5492-85f9-fa46ca3ac4ae','00000000-0000-0000-0000-00000000b005','risk-data','Rủi ro dữ liệu','risk','Watch — kỷ luật quote số liệu','[{"key":"Nguyên tắc","value":"Không quote số chưa khóa: diện tích, giá, phút di chuyển, pháp lý, lãi vay"},{"key":"Số căn","value":"Dao động 1.800–1.940 tùy tài liệu — dùng theo Q&A: 1.940"},{"key":"Nhiều sales page","value":"Dễ sinh sai lệch — bắt buộc dùng chung data room"},{"key":"Trạng thái chuẩn","value":"Đã có bản gốc / đang chờ / không dùng"}]'::jsonb,null,'Bản map càng nhiều dữ liệu nội bộ càng cần kỷ luật cao. Mỗi con số đi vào tư vấn phải có nguồn, ngày cập nhật và trạng thái — vì khách phân khúc này so sánh rất kỹ giữa các sales page.',51),
  ('f54d5c35-4d1b-55c6-a293-3e7d912b6891','00000000-0000-0000-0000-00000000b005','qa-10','10 câu Q&A đào tạo','risk',null,'[{"key":"Q1","value":"Tổng quan: D11 7m→17m, The Twin, Gateway, Icon, Crown"},{"key":"Q2","value":"Tầng hầm lệch tầng: B1 4m, B2 3m"},{"key":"Q3","value":"View The Gateway: Đông Nam / Tây Nam"},{"key":"Q4","value":"Rạp chiếu phim tầng 4–5 The Twin"},{"key":"Q5","value":"74 tiện ích + Bcons City 135 + cầu đi bộ"},{"key":"Q6","value":"TTTM The Twin 7 tầng ~48.000 m²"},{"key":"Q7","value":"Quảng trường 8.000 m², nhạc nước"},{"key":"Q8","value":"OCB bảo lãnh; VCB/MB/ACB/TPBank/Public/BIDV cho vay"},{"key":"Q9","value":"2 hồ bơi: vô cực T7 + ốc đảo"},{"key":"Q10","value":"Chủ đầu tư: Công ty CP Địa ốc Bcons"}]'::jsonb,'"Sale nào trả lời trôi chảy 10 câu này trong 15 phút là đủ khung để ra trận — phần còn lại là bảng giá hiệu lực và kịch bản xử lý phản đối ở các node rủi ro."','Mini game đào tạo 15 phút trước buổi tư vấn — đúng thứ tự: tổng quan → kỹ thuật → view → tiện ích → tài chính → chủ đầu tư. Sale trả lời được 10 câu này là nắm xong phần khung sản phẩm.',52);
